import{_ as a,o as e,c as i,ak as r}from"./chunks/framework.CrxOZ6ja.js";const p=JSON.parse('{"title":"Babel Handbook 📚","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md","lastUpdated":1775144460000}'),t={name:"README.md"};function o(b,l,n,s,c,h){return e(),i("div",null,[...l[0]||(l[0]=[r('<h1 id="babel-handbook-📚" tabindex="-1">Babel Handbook 📚 <a class="header-anchor" href="#babel-handbook-📚" aria-label="Permalink to “Babel Handbook 📚”">​</a></h1><blockquote><p>深入学习 Babel - 使用和创建 JavaScript 编译器插件</p></blockquote><p><a href="http://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer"><img src="https://licensebuttons.net/l/by/4.0/80x15.png" alt="cc-by-4.0"></a></p><p>本手册由 <a href="https://jamie.build/" target="_blank" rel="noreferrer">Jamie Kyle</a> 编写，涵盖使用 <a href="https://babeljs.io" target="_blank" rel="noreferrer">Babel</a> 及其相关工具的所有知识。 源仓库中文版有些排版问题，PR 也就不更新了。故，开出一个新仓库供大家学习参考。</p><h2 id="📖-简介" tabindex="-1">📖 简介 <a class="header-anchor" href="#📖-简介" aria-label="Permalink to “📖 简介”">​</a></h2><p>Babel 是一个通用的多用途 JavaScript 编译器。使用 Babel，您可以：</p><ul><li>🚀 使用下一代 JavaScript 语法</li><li>🔧 创建自定义转换插件</li><li>🛠️ 构建强大的 JavaScript 工具</li><li>📦 转换 ES2015+、JSX、Flow 等语法</li></ul><p>本手册分为两个部分，帮助您全面掌握 Babel。</p><h2 id="📚-内容结构" tabindex="-1">📚 内容结构 <a class="header-anchor" href="#📚-内容结构" aria-label="Permalink to “📚 内容结构”">​</a></h2><h3 id="用户手册" tabindex="-1">用户手册 <a class="header-anchor" href="#用户手册" aria-label="Permalink to “用户手册”">​</a></h3><p>用户手册涵盖 Babel 的日常使用和配置：</p><ul><li><p><strong>Babel 简介</strong></p><ul><li>JavaScript 编译的概念</li><li>源到源编译 (Transpiling)</li><li>Babel 的应用场景</li></ul></li><li><p><strong>设置 Babel</strong></p><ul><li><code>babel-cli</code> - 命令行工具</li><li><code>babel-register</code> - 运行时编译</li><li><code>babel-node</code> - 替代 Node.js REPL</li><li><code>babel-core</code> - 编程式 API</li></ul></li><li><p><strong>配置 Babel</strong></p><ul><li><code>.babelrc</code> 配置文件</li><li>Presets (预设) 的使用</li><li><code>babel-preset-es2015</code></li><li><code>babel-preset-react</code></li><li><code>babel-preset-stage-x</code></li></ul></li><li><p><strong>执行 Babel 生成代码</strong></p><ul><li><code>babel-polyfill</code> - API 支持</li><li><code>babel-runtime</code> - 辅助函数优化</li></ul></li><li><p><strong>高级配置</strong></p><ul><li>手动指定插件</li><li>插件选项</li><li>基于环境的配置</li><li>创建自定义 Preset</li></ul></li><li><p><strong>与其他工具集成</strong></p><ul><li>ESLint、JSCS</li><li>React 框架</li><li>文本编辑器和 IDE</li></ul></li></ul><h3 id="插件手册" tabindex="-1">插件手册 <a class="header-anchor" href="#插件手册" aria-label="Permalink to “插件手册”">​</a></h3><p>插件手册深入讲解如何创建自定义 Babel 插件：</p><ul><li><p><strong>基础概念</strong></p><ul><li>抽象语法树 (AST)</li><li>Babel 的三个阶段：解析、转换、生成</li><li>词法分析和语法分析</li></ul></li><li><p><strong>遍历机制</strong></p><ul><li>访问者模式</li><li>路径 (Paths)</li><li>状态管理</li><li>作用域和绑定</li></ul></li><li><p><strong>Babel API</strong></p><ul><li><code>babel-parser</code> - 解析代码</li><li><code>babel-traverse</code> - 遍历 AST</li><li><code>babel-types</code> - AST 节点操作</li><li><code>babel-generator</code> - 代码生成</li><li><code>babel-template</code> - 模板构建</li></ul></li><li><p><strong>插件开发</strong></p><ul><li>编写第一个 Babel 插件</li><li>转换操作详解</li><li>节点操作方法</li><li>作用域处理</li><li>插件选项和最佳实践</li></ul></li></ul><h2 id="🌍-语言支持" tabindex="-1">🌍 语言支持 <a class="header-anchor" href="#🌍-语言支持" aria-label="Permalink to “🌍 语言支持”">​</a></h2><p>本手册提供以下语言版本：</p><ul><li>🇺🇸 <strong>English</strong> - 英文原版</li><li>🇨🇳 <strong>简体中文</strong> - 中文翻译版</li></ul><h2 id="🎯-适合谁阅读" tabindex="-1">🎯 适合谁阅读 <a class="header-anchor" href="#🎯-适合谁阅读" aria-label="Permalink to “🎯 适合谁阅读”">​</a></h2><ul><li><strong>前端开发者</strong> - 想要了解和使用现代 JavaScript 语法</li><li><strong>工具链开发者</strong> - 需要创建代码转换工具</li><li><strong>框架作者</strong> - 需要理解 JavaScript 编译原理</li><li><strong>Babel 用户</strong> - 希望深入配置和优化 Babel</li><li><strong>插件开发者</strong> - 想要为 Babel 生态系统做贡献</li></ul><h2 id="💡-为什么选择-babel" tabindex="-1">💡 为什么选择 Babel <a class="header-anchor" href="#💡-为什么选择-babel" aria-label="Permalink to “💡 为什么选择 Babel”">​</a></h2><p>JavaScript 作为一门语言在不断演进，新的规范和提案不断推出新特性。Babel 让您能够在这些特性普及之前就使用它们，同时保持代码在现有环境中的兼容性。</p><p>通过 Babel，您可以：</p><ul><li>使用最新的 JavaScript 语法特性</li><li>编译 JSX（用于 React）</li><li>支持 Flow 类型注解</li><li>创建自定义语法转换</li><li>构建代码分析工具</li></ul><h2 id="📖-阅读建议" tabindex="-1">📖 阅读建议 <a class="header-anchor" href="#📖-阅读建议" aria-label="Permalink to “📖 阅读建议”">​</a></h2><h3 id="初学者" tabindex="-1">初学者 <a class="header-anchor" href="#初学者" aria-label="Permalink to “初学者”">​</a></h3><ol><li>从用户手册开始，了解 Babel 的基本概念</li><li>学习如何安装和配置 Babel</li><li>尝试简单的代码转换示例</li><li>逐步探索高级配置选项</li></ol><h3 id="进阶用户" tabindex="-1">进阶用户 <a class="header-anchor" href="#进阶用户" aria-label="Permalink to “进阶用户”">​</a></h3><ol><li>深入学习 AST 和编译原理</li><li>阅读插件手册，学习插件开发</li><li>实践编写自定义转换插件</li><li>研究 Babel 内部实现机制</li></ol><h3 id="工具链开发者" tabindex="-1">工具链开发者 <a class="header-anchor" href="#工具链开发者" aria-label="Permalink to “工具链开发者”">​</a></h3><ol><li>全面理解 Babel 的三个阶段</li><li>掌握所有 Babel API</li><li>学习性能优化最佳实践</li><li>为 Babel 生态系统贡献代码</li></ol><h2 id="🔗-相关资源" tabindex="-1">🔗 相关资源 <a class="header-anchor" href="#🔗-相关资源" aria-label="Permalink to “🔗 相关资源”">​</a></h2><ul><li><a href="https://babeljs.io/" target="_blank" rel="noreferrer">Babel 官方网站</a></li><li><a href="https://github.com/babel/babel" target="_blank" rel="noreferrer">Babel GitHub 仓库</a></li><li><a href="https://discuss.babeljs.io/" target="_blank" rel="noreferrer">Babel 论坛</a></li><li><a href="https://slack.babeljs.io/" target="_blank" rel="noreferrer">Babel Slack</a></li></ul><h2 id="📝-内容贡献" tabindex="-1">📝 内容贡献 <a class="header-anchor" href="#📝-内容贡献" aria-label="Permalink to “📝 内容贡献”">​</a></h2><p>如果您发现手册中有未翻译的英文部分，欢迎通过 PR 贡献翻译和补充内容。</p><h2 id="📄-许可证" tabindex="-1">📄 许可证 <a class="header-anchor" href="#📄-许可证" aria-label="Permalink to “📄 许可证”">​</a></h2><p>本手册采用 <a href="http://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">CC BY 4.0</a> 许可证发布。</p><hr><p><strong>开始学习 Babel</strong> - 掌握现代 JavaScript 开发的核心工具</p>',39)])])}const g=a(t,[["render",o]]);export{p as __pageData,g as default};
